const CLOUD_NAME="dbpxsdpvg",UPLOAD_PRESET="ml_default";export async function uploadImageToCloudinary(e){const a=new FormData;a.append("file",e),a.append("upload_preset","ml_default");const o=await fetch(`https://api.cloudinary.com/v1_1/${CLOUD_NAME}/image/upload`,{method:"POST",body:a}),r=await o.json();if(r.error)throw new Error(r.error.message);return r.secure_url}